import argparse
import copy
import os
from pathlib import Path
from typing import Optional

import torch
import torch.nn as nn
from torch.utils.data import DataLoader
from torchvision import datasets, models, transforms


def parse_args():
    parser = argparse.ArgumentParser(description="Transfer learning pipeline with safe pretrained model loading")
    parser.add_argument("--data-dir", type=str, required=True, help="Path to dataset root with train/ and val/ subfolders")
    parser.add_argument("--arch", type=str, default="resnet18", choices=[
        "resnet18", "resnet34", "resnet50",
        "mobilenet_v3_small", "mobilenet_v3_large",
        "efficientnet_b0", "densenet121"
    ])
    parser.add_argument("--num-classes", type=int, required=True)
    parser.add_argument("--batch-size", type=int, default=32)
    parser.add_argument("--epochs", type=int, default=5)
    parser.add_argument("--lr", type=float, default=1e-3)
    parser.add_argument("--num-workers", type=int, default=4)
    parser.add_argument("--image-size", type=int, default=224)
    parser.add_argument("--freeze-backbone", action="store_true")
    parser.add_argument("--checkpoint-path", type=str, default="", help="Optional local checkpoint path to initialize model")
    parser.add_argument("--save-path", type=str, default="finetuned_model.pt")
    return parser.parse_args()


def build_transforms(image_size: int):
    train_tfms = transforms.Compose([
        transforms.Resize((image_size, image_size)),
        transforms.RandomHorizontalFlip(),
        transforms.ToTensor(),
    ])
    val_tfms = transforms.Compose([
        transforms.Resize((image_size, image_size)),
        transforms.ToTensor(),
    ])
    return train_tfms, val_tfms


def build_dataloaders(data_dir: str, image_size: int, batch_size: int, num_workers: int):
    train_tfms, val_tfms = build_transforms(image_size)
    train_dir = os.path.join(data_dir, "train")
    val_dir = os.path.join(data_dir, "val")

    train_ds = datasets.ImageFolder(train_dir, transform=train_tfms)
    val_ds = datasets.ImageFolder(val_dir, transform=val_tfms)

    train_loader = DataLoader(train_ds, batch_size=batch_size, shuffle=True, num_workers=num_workers)
    val_loader = DataLoader(val_ds, batch_size=batch_size, shuffle=False, num_workers=num_workers)
    return train_loader, val_loader


def create_model(arch: str, num_classes: int, freeze_backbone: bool):
    constructors = {
        "resnet18": models.resnet18,
        "resnet34": models.resnet34,
        "resnet50": models.resnet50,
        "mobilenet_v3_small": models.mobilenet_v3_small,
        "mobilenet_v3_large": models.mobilenet_v3_large,
        "efficientnet_b0": models.efficientnet_b0,
        "densenet121": models.densenet121,
    }
    model = constructors[arch](weights="DEFAULT")

    if freeze_backbone:
        for p in model.parameters():
            p.requires_grad = False

    if arch.startswith("resnet"):
        in_features = model.fc.in_features
        model.fc = nn.Linear(in_features, num_classes)
    elif arch.startswith("mobilenet_v3"):
        in_features = model.classifier[-1].in_features
        model.classifier[-1] = nn.Linear(in_features, num_classes)
    elif arch.startswith("efficientnet"):
        in_features = model.classifier[-1].in_features
        model.classifier[-1] = nn.Linear(in_features, num_classes)
    elif arch.startswith("densenet"):
        in_features = model.classifier.in_features
        model.classifier = nn.Linear(in_features, num_classes)
    else:
        raise ValueError(f"Unsupported architecture: {arch}")

    return model


def safe_load_checkpoint(model: nn.Module, checkpoint_path: Optional[str], device: torch.device):
    if not checkpoint_path:
        return model

    checkpoint_path = str(Path(checkpoint_path).expanduser().resolve())
    obj = torch.load(checkpoint_path, map_location=device, weights_only=True)

    if isinstance(obj, dict):
        if "state_dict" in obj and isinstance(obj["state_dict"], dict):
            state_dict = obj["state_dict"]
        elif all(isinstance(k, str) for k in obj.keys()):
            state_dict = obj
        else:
            raise ValueError("Unsupported checkpoint format")
    else:
        raise ValueError("Checkpoint must contain a state dict")

    cleaned = {}
    for k, v in state_dict.items():
        nk = k.replace("module.", "", 1) if k.startswith("module.") else k
        cleaned[nk] = v

    missing, unexpected = model.load_state_dict(cleaned, strict=False)
    if missing:
        print(f"Missing keys: {missing}")
    if unexpected:
        print(f"Unexpected keys: {unexpected}")
    return model


def evaluate(model: nn.Module, loader: DataLoader, criterion, device: torch.device):
    model.eval()
    total_loss = 0.0
    correct = 0
    total = 0

    with torch.no_grad():
        for images, targets in loader:
            images = images.to(device)
            targets = targets.to(device)

            outputs = model(images)
            loss = criterion(outputs, targets)

            total_loss += loss.item() * images.size(0)
            preds = outputs.argmax(dim=1)
            correct += (preds == targets).sum().item()
            total += targets.size(0)

    return total_loss / max(total, 1), correct / max(total, 1)


def train(model: nn.Module, train_loader: DataLoader, val_loader: DataLoader, epochs: int, lr: float, device: torch.device):
    criterion = nn.CrossEntropyLoss()
    params = [p for p in model.parameters() if p.requires_grad]
    optimizer = torch.optim.Adam(params, lr=lr)

    best_acc = 0.0
    best_state = copy.deepcopy(model.state_dict())

    for epoch in range(epochs):
        model.train()
        running_loss = 0.0
        running_correct = 0
        running_total = 0

        for images, targets in train_loader:
            images = images.to(device)
            targets = targets.to(device)

            optimizer.zero_grad()
            outputs = model(images)
            loss = criterion(outputs, targets)
            loss.backward()
            optimizer.step()

            running_loss += loss.item() * images.size(0)
            preds = outputs.argmax(dim=1)
            running_correct += (preds == targets).sum().item()
            running_total += targets.size(0)

        train_loss = running_loss / max(running_total, 1)
        train_acc = running_correct / max(running_total, 1)
        val_loss, val_acc = evaluate(model, val_loader, criterion, device)

        print(
            f"Epoch {epoch + 1}/{epochs} "
            f"train_loss={train_loss:.4f} train_acc={train_acc:.4f} "
            f"val_loss={val_loss:.4f} val_acc={val_acc:.4f}"
        )

        if val_acc > best_acc:
            best_acc = val_acc
            best_state = copy.deepcopy(model.state_dict())

    model.load_state_dict(best_state)
    return model, best_acc


def main():
    args = parse_args()
    device = torch.device("cuda" if torch.cuda.is_available() else "cpu")

    train_loader, val_loader = build_dataloaders(
        args.data_dir, args.image_size, args.batch_size, args.num_workers
    )

    model = create_model(args.arch, args.num_classes, args.freeze_backbone)
    model = safe_load_checkpoint(model, args.checkpoint_path, device)
    model = model.to(device)

    model, best_acc = train(
        model, train_loader, val_loader, args.epochs, args.lr, device
    )

    save_obj = {
        "arch": args.arch,
        "num_classes": args.num_classes,
        "state_dict": model.state_dict(),
        "best_val_acc": best_acc,
    }
    torch.save(save_obj, args.save_path)
    print(f"Saved fine-tuned model to {args.save_path} with best_val_acc={best_acc:.4f}")


if __name__ == "__main__":
    main()